// 메이크샵 그룹 목록에서 강사회원 그룹코드 추출
const resp = $json;
const groups = (resp && resp.list) ? resp.list : [];
let groupCode = 'MX01'; // 기본 폴백값

const found = groups.find(function(g) {
  return g.group_name === '강사회원';
});
if (found && found.group_id) {
  groupCode = found.group_id;
}

return { json: { instructorGroupCode: groupCode } };

// NocoDB 응답 list를 개별 레코드 아이템으로 분리
const response = $input.first().json;
const records = (response.list || []);
return records.map(function(r) { return { json: r }; });

// ===== NocoDB 레코드에서 식별 정보 추출 =====
// NocoDB 레코드: Id(정수), 성함, 연락처, 자사몰 ID, 이메일 주소, 소속 협회 등
const recordId = $json.Id; // NocoDB 정수 ID (대문자 I)

const jasamolId = ($json['자사몰 ID'] || '').trim().toLowerCase();
const rawMobile = ($json['연락처'] || '').trim();
const name = ($json['성함'] || '').trim();
const email = ($json['이메일 주소'] || '').trim();
const association = ($json['소속 협회'] || '').trim();

// 연락처 정규화: 010-1234-5678 또는 01012345678 → 01012345678
const mobile = rawMobile.replace(/[^0-9]/g, '').replace(/^82/, '0');

return {
  json: {
    jasamolId,
    mobile,
    name,
    email,
    association,
    recordId,
    hasId: jasamolId.length > 0,
    hasMobile: mobile.length >= 10
  }
};

// ===== 메이크샵 회원 조회 응답 파싱 (ID 기준) =====
const resp = $json;
const originalData = $('식별 정보 추출').item.json;

let userFound = false;
let makeshopUserId = '';

// 실제 메이크샵 API 응답: {return_code: '0000', list: [{id, hname, grade, ...}]}
if (resp.return_code === '0000' && Array.isArray(resp.list) && resp.list.length > 0) {
  userFound = true;
  makeshopUserId = resp.list[0].id || originalData.jasamolId;
}

return {
  json: {
    ...originalData,
    userFound,
    makeshopUserId: makeshopUserId || originalData.jasamolId,
    failReason: userFound ? '' : '자사몰 ID로 회원을 찾지 못함: ' + originalData.jasamolId
  }
};

// ===== 연락처 조회 파싱 + 스마트 매칭 (v4.0) =====
const resp = $json;
const orig = $('식별 정보 추출').item.json;

let userFound = false;
let makeshopUserId = '';
let respName = '';
let autoApprove = false;
let nameWarning = '';
let candidateInfo = '';
let resultCount = 0;

if (resp.return_code === '0000' && Array.isArray(resp.list) && resp.list.length > 0) {
  userFound = true;
  resultCount = resp.list.length;

  if (resultCount === 1) {
    // A1: 1명이면 이름 무시 자동 승인
    makeshopUserId = resp.list[0].id || '';
    respName = (resp.list[0].hname || '').trim();
    autoApprove = true;
    const inputN = orig.name.replace(/\s/g, '');
    const apiN = respName.replace(/\s/g, '');
    if (inputN !== apiN) {
      nameWarning = '\u26a0\ufe0f 이름 불일치 (신청: ' + orig.name + ' / 메이크샵: ' + respName + ')';
    }
  } else {
    // A4: 여러 명 → 유사 이름 매칭
    const inputN = orig.name.replace(/\s/g, '').toLowerCase();
    for (const m of resp.list) {
      const apiN = (m.hname || '').replace(/\s/g, '').toLowerCase();
      if (apiN === inputN || apiN.includes(inputN) || inputN.includes(apiN)) {
        makeshopUserId = m.id || '';
        respName = (m.hname || '').trim();
        autoApprove = true;
        break;
      }
    }
    if (!autoApprove) {
      candidateInfo = resp.list.map(function(m) {
        return '  \u2022 ID: ' + m.id + ' / ' + (m.hname || '-');
      }).join('\n');
    }
  }
}

const failReason = !userFound
  ? '연락처로 회원을 찾지 못함: ' + orig.mobile
  : !autoApprove
    ? '연락처 ' + resultCount + '명 중 이름 매칭 실패 (신청: ' + orig.name + ')'
    : '';

return {
  json: {
    ...orig,
    userFound,
    autoApprove,
    makeshopUserId,
    apiName: respName,
    nameWarning,
    candidateInfo,
    resultCount,
    failReason
  }
};

// ===== 그룹 변경 API 응답 파싱 =====
// 실제 메이크샵 응답: {return_code: '0000', datas: [{result: 'true'/'false', userid, group_id, group_name, message}]}
// 주의: result는 boolean이 아닌 string 'true'/'false'
const resp = $json;

let success = false;
let failMessage = '';

if (resp.return_code === '0000' && Array.isArray(resp.datas) && resp.datas.length > 0) {
  const item = resp.datas[0];
  // result는 string 'true' 또는 boolean true 둘 다 처리
  if (item.result === true || item.result === 'true') {
    success = true;
  } else {
    const msgs = item.message || [];
    failMessage = Array.isArray(msgs) ? msgs.join(', ') : String(msgs);
  }
}

// 이전 노드 데이터 유지 (두 경로 모두 try-catch로 안전하게)
let prevData = {};
try { prevData = { ...prevData, ...$('조회 응답 파싱 (ID)').item.json }; } catch(e) {}
try { prevData = { ...prevData, ...$('연락처 조회 파싱 (스마트 매칭)').item.json }; } catch(e) {}
try { prevData = { ...prevData, ...$('이메일 조회 파싱').item.json }; } catch(e) {}

return {
  json: {
    ...prevData,
    groupChangeSuccess: success,
    groupChangeFailMessage: failMessage,
    groupChangeResponse: JSON.stringify(resp)
  }
};

// 같은 신청 건의 승인 메일 성공 이력이 있으면 자동 재발송 차단
var data = $('그룹 변경 응답 파싱').item.json || {};
var staticData = $getWorkflowStaticData('global');
var ledger = staticData.mailSuccessLedger;

if (!ledger || typeof ledger !== 'object' || Array.isArray(ledger)) {
  ledger = {};
}

var guardKey = 'FA-001:' + String(data.recordId || '');
var lastSuccess = ledger[guardKey] || null;

return {
  json: {
    ...data,
    mailGuardKey: guardKey,
    duplicateBlocked: !!lastSuccess,
    lastSuccessAt: lastSuccess ? String(lastSuccess.sentAt || '') : '',
    lastSuccessEmail: lastSuccess ? String(lastSuccess.email || '') : '',
    lastSuccessName: lastSuccess ? String(lastSuccess.name || '') : ''
  }
};

// ===== 수동 처리 요청 메시지 조립 (v4.0) =====
// C1 버그 수정: 마지막 단계 failReason 우선
let data = {};
let lastFail = '';

try { data = $('식별 정보 추출').item.json; } catch(e) {}
try {
  const d = $('이메일 조회 파싱').item.json;
  data = { ...data, ...d };
  if (d.failReason) lastFail = d.failReason;
} catch(e) {}
try {
  const d = $('연락처 조회 파싱 (스마트 매칭)').item.json;
  data = { ...data, ...d };
  if (d.failReason && !lastFail) lastFail = d.failReason;
} catch(e) {}
try {
  const d = $('그룹 변경 응답 파싱').item.json;
  data = { ...data, ...d };
  if (d.groupChangeFailMessage) lastFail = '그룹 변경 API 실패: ' + d.groupChangeFailMessage;
} catch(e) {}
try {
  const d = $('조회 응답 파싱 (ID)').item.json;
  if (!lastFail && d.failReason) lastFail = d.failReason;
} catch(e) {}

const reason = lastFail || data.failReason || '원인 불명';
const name = data.name || '(이름 없음)';
const jasamolId = data.jasamolId || '(미입력)';
const mobile = data.mobile || '(미입력)';
const email = data.email || '(미입력)';
const association = data.association || '(미입력)';
const recordId = data.recordId || '';
const candidateInfo = data.candidateInfo || '';
const candidateId = data.makeshopUserId || '';

let msg = '\u26a0\ufe0f 강사 등업 수동 처리 필요\n\n이름: ' + name + '\n자사몰ID: ' + jasamolId + '\n연락처: ' + mobile + '\n이메일: ' + email + '\n협회: ' + association + '\n\n사유: ' + reason;

if (candidateInfo) {
  msg += '\n\n\ud83d\udccb 검색된 후보 회원:\n' + candidateInfo;
}

msg += '\n\n\u2192 메이크샵 관리자에서 직접 등업 후\nNocoDB n8n_처리완료 체크 바랍니다';

const kst = new Date(new Date().getTime() + 9*60*60*1000).toISOString();
const hasCandidate = candidateId.length > 0;

return {
  json: {
    message: msg,
    id: recordId,
    n8n_처리완료: true,
    n8n_처리일시: kst,
    hasCandidate,
    candidateId,
    candidateName: name,
    callbackData: hasCandidate ? 'fa001:' + recordId + ':' + candidateId : ''
  }
};

// 승인 메일 발송 결과 기록 및 성공 발송 ledger 반영
var item = $input.item.json || {};
var prevData = $('승인 메일 중복 발송 가드').item.json || $('그룹 변경 응답 파싱').item.json || {};
var errorMessage = '';

if (typeof item.error === 'string' && item.error) {
  errorMessage = item.error;
} else if (Array.isArray(item.rejected) && item.rejected.length > 0) {
  errorMessage = 'Rejected: ' + item.rejected.join(', ');
}

var emailSuccess = errorMessage === '';
var staticData = $getWorkflowStaticData('global');
var ledger = staticData.mailSuccessLedger;
if (!ledger || typeof ledger !== 'object' || Array.isArray(ledger)) {
  ledger = {};
}
var attemptLog = Array.isArray(staticData.mailAttemptLog) ? staticData.mailAttemptLog : [];
var sentAt = new Date(new Date().getTime() + 9 * 60 * 60 * 1000).toISOString();
var guardKey = String(prevData.mailGuardKey || ('FA-001:' + String(prevData.recordId || '')));

attemptLog.unshift({
  key: guardKey,
  workflow: 'FA-001',
  status: emailSuccess ? 'success' : 'failed',
  sentAt: sentAt,
  recordId: String(prevData.recordId || ''),
  email: String(prevData.email || ''),
  name: String(prevData.name || '')
});
staticData.mailAttemptLog = attemptLog.slice(0, 200);

if (emailSuccess) {
  ledger[guardKey] = {
    workflow: 'FA-001',
    recordId: String(prevData.recordId || ''),
    email: String(prevData.email || ''),
    name: String(prevData.name || ''),
    subject: '[PRESSCO21] 강사회원 등업이 완료되었습니다',
    sentAt: sentAt
  };
  staticData.mailSuccessLedger = ledger;
}

return {
  json: {
    recordId: prevData.recordId,
    name: prevData.name,
    email: prevData.email,
    makeshopUserId: prevData.makeshopUserId,
    association: prevData.association,
    emailSuccess: emailSuccess,
    errorMessage: errorMessage
  }
};

// ===== 이메일 조회 파싱 (v4.0) =====
const resp = $json;
const orig = $('식별 정보 추출').item.json;

let userFound = false;
let makeshopUserId = '';
let respName = '';
let autoApprove = false;
let candidateInfo = '';

if (resp.return_code === '0000' && Array.isArray(resp.list) && resp.list.length > 0) {
  userFound = true;
  if (resp.list.length === 1) {
    makeshopUserId = resp.list[0].id || '';
    respName = (resp.list[0].hname || '').trim();
    autoApprove = true;
  } else {
    const inputN = orig.name.replace(/\s/g, '').toLowerCase();
    for (const m of resp.list) {
      const apiN = (m.hname || '').replace(/\s/g, '').toLowerCase();
      if (apiN === inputN || apiN.includes(inputN) || inputN.includes(apiN)) {
        makeshopUserId = m.id || '';
        respName = (m.hname || '').trim();
        autoApprove = true;
        break;
      }
    }
    if (!autoApprove) {
      candidateInfo = resp.list.map(function(m) {
        return '  \u2022 ID: ' + m.id + ' / ' + (m.hname || '-');
      }).join('\n');
    }
  }
}

// 이전 연락처 검색 후보 정보 병합
let prevCandidate = '';
try { prevCandidate = $('연락처 조회 파싱 (스마트 매칭)').item.json.candidateInfo || ''; } catch(e) {}
if (prevCandidate && candidateInfo) candidateInfo = prevCandidate + '\n' + candidateInfo;
else if (prevCandidate) candidateInfo = prevCandidate;

const failReason = !userFound
  ? '이메일로도 회원을 찾지 못함: ' + orig.email
  : !autoApprove
    ? '이메일 검색 ' + resp.list.length + '명 중 이름 매칭 실패'
    : '';

return {
  json: {
    ...orig,
    userFound,
    autoApprove,
    makeshopUserId,
    apiName: respName,
    candidateInfo,
    failReason
  }
};
